-- ── AppDirect ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$AppDirect is a B2B subscription commerce platform that helps telecom carriers, technology providers, and advisors sell, bundle, and manage recurring technology and connectivity services.$q$, short_description),
  pricing_model = COALESCE($q$custom$q$, pricing_model),
  starting_price = COALESCE(NULL, starting_price),
  founded_year = COALESCE(2009, founded_year),
  company_size = COALESCE($q$approx 1,000 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$AppDirect Review 2026: Subscription Commerce Platform$q$, seo_title),
  seo_meta_description = COALESCE($q$AppDirect is a B2B subscription commerce platform for telecom and tech companies. See 2026 pricing, features, funding history, and how it compares.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$AppDirect is a San Francisco-based B2B subscription commerce platform founded in 2009 by Nicolas Desmarais, Daniel Saks, and Andy Sen. Originally known for operating a SaaS marketplace that let independent software vendors distribute cloud applications through resellers, AppDirect has since repositioned itself as a subscription commerce and monetization platform primarily serving telecommunications carriers, connectivity providers, managed service providers, and technology advisors. The platform lets these companies build white-labeled marketplaces to bundle and sell recurring technology services such as software, connectivity, devices, and even energy products to their business customers, alongside procurement and IT lifecycle management tools for the buying side. Notable customers referenced in AppDirect materials include large telecom operators such as Vodafone and Deutsche Telekom. The company has raised substantial venture funding, reportedly around $465 million in disclosed equity financing across multiple rounds (with some aggregated funding figures reported near $1.1 billion including debt and secondary activity), including a $185 million round in 2020 from Caisse de dépôt et placement du Québec and existing investors that helped push its valuation to unicorn status. By 2024, AppDirect was reported to have reached a valuation of roughly $1.5 billion with annual revenue around $227 million. AppDirect does not publish public pricing; it operates on a custom, enterprise sales model where pricing depends on transaction volume, the number of catalog products, and the scope of platform customization, typically sold via annual contracts with a guided demo and onboarding process rather than self-serve signup. The platform is not aimed at individual consumers or small businesses buying software directly; instead it is infrastructure that telecom and technology companies use to run their own commerce experience for their customers. As such, AppDirect competes less with consumer-facing marketplaces and more with other B2B subscription billing and commerce infrastructure vendors, as well as with the in-house commerce systems that large telecom operators sometimes build themselves. Its value proposition centers on speed to market for launching a branded marketplace, prebuilt catalog integrations with major software and cloud vendors, and billing/provisioning automation for recurring technology services, rather than being a tool an end business would buy off the shelf like typical SaaS.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'cb6e4649-6cc1-4673-ab1d-33f9a1308e33';

